--Drop table
IF EXISTS (
    SELECT 1
    FROM INFORMATION_SCHEMA.TABLES
    WHERE  TABLE_SCHEMA='edw_stage'
    AND TABLE_NAME = 'OneShieldPolicy_clue' 
) 
BEGIN
    DROP TABLE edw_stage.OneShieldPolicy_clue
END

--Create table
CREATE TABLE edw_stage.OneShieldPolicy_clue
(
    policy_no varchar(255),
    product varchar(255),
    risk_address varchar(255),
    home_no varchar(255),
    address_nm varchar(255),
    unit_no varchar(255),
    city_nm varchar(255),
    state_cd varchar(255),
    zip_cd varchar(255)
)
;


